import heapq
from collections import defaultdict

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size + 1))
            self.rank = [1] * (size + 1)

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1

    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    components = defaultdict(list)
    for i in range(1, c + 1):
        root = dsu.find(i)
        components[root].append(i)

    component_heaps = {}
    for root in components:
        heap = components[root].copy()
        heapq.heapify(heap)
        component_heaps[root] = heap

    online = [True] * (c + 1)
    res = []
    for q in queries:
        if q[0] == 1:
            x = q[1]
            if online[x]:
                res.append(x)
            else:
                root = dsu.find(x)
                heap = component_heaps[root]
                while heap:
                    current = heap[0]
                    if online[current]:
                        res.append(current)
                        break
                    else:
                        heapq.heappop(heap)
                else:
                    res.append(-1)
        else:
            x = q[1]
            online[x] = False
    return res
